I now have a thorough understanding of the entire codebase. Here is the complete implementation plan.

---

## Implementation Plan: Stepper Compound Component

### Architecture Overview

The Stepper is a pure-React compound component (no Radix primitive) using a two-level context system: one root context for orientation and active-step control, and one per-item context so each sub-component can derive its own state. The pattern is closely modelled on `carousel.tsx` (custom context, no Radix) and `tabs.tsx` (orientation via group/data attributes). The separator follows the same orientation-aware pattern as `separator.tsx`.

---

### 1. `apps/v4/registry/new-york-v4/ui/stepper.tsx`

**Complete production-quality code:**

```tsx
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Root Context ────────────────────────────────────────────────────────────

type StepperContextValue = {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue>({
  value: 0,
  onValueChange: () => {},
  orientation: "horizontal",
})

function useStepper() {
  return React.useContext(StepperContext)
}

// ─── Item Context ─────────────────────────────────────────────────────────────

type StepperItemContextValue = {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue>({
  step: 0,
  isActive: false,
  isCompleted: false,
})

function useStepperItem() {
  return React.useContext(StepperItemContext)
}

// ─── Stepper (root) ──────────────────────────────────────────────────────────

function Stepper({
  className,
  value = 0,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const handleValueChange = React.useCallback(
    (newValue: number) => {
      onValueChange?.(newValue)
    },
    [onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start",
          "data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

function StepperItem({
  className,
  step,
  completed = false,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  completed?: boolean
}) {
  const { value, orientation } = useStepper()
  const isActive = value === step
  const isCompleted = completed || value > step

  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-step={step}
        className={cn(
          "group/stepper-item flex",
          "group-data-[orientation=horizontal]/stepper:flex-col group-data-[orientation=horizontal]/stepper:items-center",
          "group-data-[orientation=vertical]/stepper:flex-row group-data-[orientation=vertical]/stepper:items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      onClick={() => onValueChange(step)}
      className={cn(
        "inline-flex items-center gap-2 rounded-md text-sm font-medium outline-none transition-colors",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      <span
        className={cn(
          "flex size-7 shrink-0 items-center justify-center rounded-full border text-xs font-semibold transition-colors",
          isCompleted &&
            "border-primary bg-primary text-primary-foreground",
          isActive &&
            !isCompleted &&
            "border-primary bg-background text-primary ring-2 ring-primary/20",
          !isActive &&
            !isCompleted &&
            "border-muted-foreground/30 bg-muted text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <CheckIcon className="size-3.5" />
        ) : (
          <span>{step + 1}</span>
        )}
      </span>
      {children}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-semibold leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      aria-hidden
      className={cn(
        "bg-border transition-colors",
        "group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:flex-1",
        "group-data-[orientation=vertical]/stepper:w-px group-data-[orientation=vertical]/stepper:h-full group-data-[orientation=vertical]/stepper:self-stretch group-data-[orientation=vertical]/stepper:ml-3.5 group-data-[orientation=vertical]/stepper:my-1 group-data-[orientation=vertical]/stepper:min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = useStepperItem()

  return (
    <div
      data-slot="stepper-content"
      data-state={isActive ? "active" : "inactive"}
      className={cn(
        "data-[state=inactive]:hidden",
        className
      )}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

**Key design decisions in this file:**

- `useStepper()` and `useStepperItem()` are internal hooks (not exported). They do not throw — they return defaults instead — which is appropriate since they are only consumed by the co-located sub-components and the defaults are safe no-ops.
- `StepperItem` derives `isCompleted` from EITHER the explicit `completed` prop OR from `value > step`, so both controlled and prop-driven completion work.
- `StepperTrigger` wraps children in a `<span>` indicator, keeping the indicator as an intrinsic part of every trigger rather than a separate exported sub-component (following the accordion chevron pattern).
- `StepperSeparator` reads orientation exclusively from the root group CSS selectors (`group-data-[orientation=...]/stepper:`), mirroring how `tabs.tsx` propagates orientation downward without passing context manually.
- `StepperContent` reads `isActive` from item context and toggles `data-[state=inactive]:hidden`, identical to how Accordion/Tabs use Radix-managed state.

---

### 2. `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

**Complete code:**

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    title: "Your details",
    description: "Name and email address",
  },
  {
    title: "Company info",
    description: "Your role and team size",
  },
  {
    title: "Invite team",
    description: "Start collaborating",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  function handleNext() {
    setActiveStep((prev) => Math.min(prev + 1, steps.length - 1))
  }

  function handleBack() {
    setActiveStep((prev) => Math.max(prev - 1, 0))
  }

  return (
    <div className="flex w-full max-w-xl flex-col gap-8">
      <Stepper value={activeStep} onValueChange={setActiveStep}>
        {steps.map((step, index) => (
          <React.Fragment key={step.title}>
            <StepperItem step={index} className="flex-1">
              <StepperTrigger>
                <div className="flex flex-col items-start gap-0.5 text-left">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
              <StepperContent className="mt-4 px-1">
                <div className="rounded-lg border bg-muted/40 p-4 text-sm text-muted-foreground">
                  Content for &ldquo;{step.title}&rdquo; goes here.
                </div>
                <div className="mt-4 flex gap-2">
                  {index > 0 && (
                    <Button variant="outline" size="sm" onClick={handleBack}>
                      Back
                    </Button>
                  )}
                  {index < steps.length - 1 ? (
                    <Button size="sm" onClick={handleNext}>
                      Continue
                    </Button>
                  ) : (
                    <Button size="sm" onClick={() => setActiveStep(0)}>
                      Finish
                    </Button>
                  )}
                </div>
              </StepperContent>
            </StepperItem>
            {index < steps.length - 1 && (
              <StepperSeparator className="mt-3.5" />
            )}
          </React.Fragment>
        ))}
      </Stepper>
    </div>
  )
}
```

**Key demo design decisions:**

- Uses `"use client"` because `useState` is required.
- Import path follows the `@/registry/new-york-v4/ui/stepper` pattern confirmed from other demos.
- The `steps` array is defined outside the component to avoid recreation on re-render.
- `StepperContent` is rendered inside `StepperItem` so it naturally inherits item context.
- Navigation buttons are inside `StepperContent`, so only the active step shows them.
- The separator is placed between items (not inside them), using `React.Fragment` — identical to how accordion/tab separators work as siblings.
- "Finish" resets to step 0, giving a complete demo loop.

