  const [activeStep, setActiveStep] = React.useState(0)

  function handleNext() {
    setActiveStep((prev) => Math.min(prev + 1, steps.length - 1))
  }

  function handleBack() {
    setActiveStep((prev) => Math.max(prev - 1, 0))
