# Plan: Add Stepper Compound Component

## Context

The shadcn/ui library (`apps/v4/registry/new-york-v4/`) has no stepper component. This plan adds one for multi-step wizards and onboarding flows. Because no Radix UI primitive for steppers exists, the component uses a two-level React context for state management (root context for orientation/active-step; item context so each sub-component knows its own state). All other conventions mirror the existing compound components exactly (`accordion.tsx`, `tabs.tsx`).

**Constraint**: Do NOT modify any existing files. Only create new files and add registry entries.

---

## Files to Create

1. `apps/v4/registry/new-york-v4/ui/stepper.tsx` — component
2. `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` — demo

## Files to Edit (registry entries only)

3. `apps/v4/registry/new-york-v4/ui/_registry.ts` — insert between "spinner" and "switch"
4. `apps/v4/registry/new-york-v4/examples/_registry.ts` — insert between "switch-demo" and "table-demo"

---

## Step 1 — Create `ui/stepper.tsx`

Full path: `apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Root Context ─────────────────────────────────────────────────────────────

type StepperContextValue = {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue>({
  value: 0,
  onValueChange: () => {},
  orientation: "horizontal",
})

function useStepper() {
  return React.useContext(StepperContext)
}

// ─── Item Context ─────────────────────────────────────────────────────────────

type StepperItemContextValue = {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue>({
  step: 0,
  isActive: false,
  isCompleted: false,
})

function useStepperItem() {
  return React.useContext(StepperItemContext)
}

// ─── Stepper (root) ───────────────────────────────────────────────────────────

function Stepper({
  className,
  value = 0,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const handleValueChange = React.useCallback(
    (newValue: number) => {
      onValueChange?.(newValue)
    },
    [onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start",
          "data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

function StepperItem({
  className,
  step,
  completed = false,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  completed?: boolean
}) {
  const { value } = useStepper()
  const isActive = value === step
  const isCompleted = completed || value > step
  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-step={step}
        className={cn(
          "group/stepper-item flex",
          "group-data-[orientation=horizontal]/stepper:flex-col group-data-[orientation=horizontal]/stepper:items-center",
          "group-data-[orientation=vertical]/stepper:flex-row group-data-[orientation=vertical]/stepper:items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      onClick={() => onValueChange(step)}
      className={cn(
        "inline-flex items-center gap-2 rounded-md text-sm font-medium outline-none transition-colors",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      <span
        className={cn(
          "flex size-7 shrink-0 items-center justify-center rounded-full border text-xs font-semibold transition-colors",
          isCompleted && "border-primary bg-primary text-primary-foreground",
          isActive &&
            !isCompleted &&
            "border-primary bg-background text-primary ring-2 ring-primary/20",
          !isActive &&
            !isCompleted &&
            "border-muted-foreground/30 bg-muted text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <CheckIcon className="size-3.5" />
        ) : (
          <span>{step + 1}</span>
        )}
      </span>
      {children}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-semibold leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      aria-hidden
      className={cn(
        "bg-border transition-colors",
        "group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:flex-1",
        "group-data-[orientation=vertical]/stepper:w-px group-data-[orientation=vertical]/stepper:h-full group-data-[orientation=vertical]/stepper:self-stretch group-data-[orientation=vertical]/stepper:ml-3.5 group-data-[orientation=vertical]/stepper:my-1 group-data-[orientation=vertical]/stepper:min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = useStepperItem()

  return (
    <div
      data-slot="stepper-content"
      data-state={isActive ? "active" : "inactive"}
      className={cn("data-[state=inactive]:hidden", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

### Design decisions
- **Two-level context**: `StepperContext` (root) holds `value`, `onValueChange`, `orientation`. `StepperItemContext` (per-item) holds `step`, `isActive`, `isCompleted`. Internal hooks `useStepper()` / `useStepperItem()` are not exported — same pattern as `carousel.tsx`.
- **`isCompleted` logic**: derived as `completed || value > step`, so both explicit prop control and implicit linear progression work.
- **Orientation propagation**: via CSS `group-data-[orientation=...]/stepper:` selectors — no prop drilling — same as `tabs.tsx`.
- **`StepperTrigger` indicator**: the circular step-number/checkmark is an intrinsic part of the trigger (not a separate exported sub-component), mirroring the accordion chevron pattern.
- **`StepperContent`**: hides via `data-[state=inactive]:hidden` — same pattern as Accordion/Tabs using Radix-managed state.
- **Vertical separator alignment**: `ml-3.5` = half of `size-7` (28px / 2 = 14px = 3.5rem units), aligns the line under the center of the circular indicator.

