"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type Orientation = "horizontal" | "vertical"

interface StepperContextValue {
  value: number
  onValueChange: (value: number) => void
  orientation: Orientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("Stepper sub-components must be used inside <Stepper>")
  }
  return context
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItemContext() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error(
      "StepperItem sub-components must be used inside <StepperItem>"
    )
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

interface StepperProps extends React.ComponentProps<"div"> {
  value?: number
  defaultValue?: number
  onValueChange?: (value: number) => void
  orientation?: Orientation
}

function Stepper({
  value: valueProp,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (next: number) => {
      if (!isControlled) setInternalValue(next)
      onValueChange?.(next)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-stretch",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  step: number
  completed?: boolean
  disabled?: boolean
}

function StepperItem({
  step,
  completed: completedProp,
  disabled,
  className,
  ...props
}: StepperItemProps) {
  const { value, orientation } = useStepperContext()
  const isActive = value === step
  const isCompleted = completedProp ?? value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        data-disabled={disabled ? "" : undefined}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row items-start",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepperContext()
  const { step, isActive, isCompleted } = useStepperItemContext()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      onClick={() => onValueChange(step)}
      className={cn(
        "group/stepper-trigger inline-flex items-center gap-3 rounded-md text-sm font-medium transition-colors outline-none",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        "group-data-[orientation=horizontal]/stepper-item:flex-col group-data-[orientation=horizontal]/stepper-item:gap-2",
        className
      )}
      {...props}
    >
      {/* Step indicator circle */}
      <span
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
          isCompleted
            ? "border-primary bg-primary text-primary-foreground"
            : isActive
              ? "border-primary bg-primary text-primary-foreground"
              : "border-muted-foreground/40 bg-background text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <CheckIcon className="size-4" />
        ) : (
          <span>{step}</span>
        )}
      </span>
      {/* Title / description slot */}
      {children && (
        <span className="flex flex-col group-data-[orientation=horizontal]/stepper-item:items-center">
          {children}
        </span>
      )}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { isActive, isCompleted } = useStepperItemContext()
  return (
    <span
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none",
        isActive || isCompleted ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepperContext()
  const { isCompleted } = useStepperItemContext()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "rounded-full transition-colors",
        orientation === "horizontal"
          ? "mt-4 h-0.5 flex-1"
          : "ms-4 w-0.5 flex-1 self-stretch",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = useStepperItemContext()

  return (
    <div
      data-slot="stepper-content"
      data-state={isActive ? "active" : "inactive"}
      className={cn(
        "mt-2 text-sm text-muted-foreground",
        "data-[state=inactive]:hidden",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

