"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content:
      "Enter your name and email address to create a new account. You'll use these to sign in later.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content:
      "Add a profile photo and a short bio so others can learn more about you.",
  },
  {
    step: 3,
    title: "Confirm",
    description: "Review & confirm",
    content:
      "Review your details and confirm everything looks correct before finishing.",
  },
]

export default function StepperDemo() {
  const [value, setValue] = React.useState(1)

  return (
    <div className="flex w-full max-w-2xl flex-col gap-8">
      {/* Horizontal stepper */}
      <Stepper value={value} onValueChange={setValue} orientation="horizontal">
        {steps.map(({ step, title, description, content }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step} className="flex-1">
              <StepperTrigger>
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </StepperTrigger>
              <StepperContent>{content}</StepperContent>
            </StepperItem>
            {index < steps.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      <div className="flex gap-2">
        <Button
          variant="outline"
          size="sm"
          disabled={value <= 1}
          onClick={() => setValue((v) => Math.max(1, v - 1))}
        >
          Back
        </Button>
        <Button
          size="sm"
          disabled={value >= steps.length}
          onClick={() => setValue((v) => Math.min(steps.length, v + 1))}
        >
          {value === steps.length ? "Finish" : "Next"}
        </Button>
      </div>

      {/* Vertical stepper */}
      <Stepper value={value} onValueChange={setValue} orientation="vertical">
        {steps.map(({ step, title, description, content }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step}>
              <StepperTrigger>
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </StepperTrigger>
              <StepperContent>{content}</StepperContent>
            </StepperItem>
            {index < steps.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>
    </div>
  )
}

